css:
.loader {
  display: inline-block;
  width: 66px;
  height: 66px;
  border-radius: 50%;
  border: 5px solid color-mix(in srgb, var(--loader-secondary-color) 35%, transparent);
  border-top-color: var(--loader-color);
  border-right-color: var(--loader-color);
  animation: spin 1.13s cubic-bezier(.55,.15,.45,.85) infinite;
}
.loader::after {
  content: "";
  display: block;
  width: calc(100% - 16px);
  height: calc(100% - 16px);
  margin: 4px;
  border-radius: 50%;
  border: 4px solid transparent;
  border-bottom-color: var(--loader-secondary-color);
  animation: spin 0.79s linear infinite reverse;
}
@keyframes spin { to { transform: rotate(360deg); } }
